// @kern-source: stages:7
function formatDispatchError(err: unknown): string {
  const message = err instanceof Error ? err.message : String(err);
  const record = err as any;
  const snippet = record?.stdout
    ? String(record.stdout).slice(0, 240).replace(/\s+/g, ' ').trim()
    : record?.stderr
      ? String(record.stderr).slice(0, 240).replace(/\s+/g, ' ').trim()
      : '';
  if (snippet) {
    return `${message} | snippet: ${snippet}${record?.stdout?.length > 240 || record?.stderr?.length > 240 ? '…' : ''}`;
  }
  return message;
}

