export async function runForgeEngineAttempt(opts: {engineId:string,prompt:string,dispatchMode:'exec'|'review',metricPhase:'stage1'|'stage2-scout'|'stage2-follower',fitnessCmd:string,config:Required<AgonConfig>,registry:EngineRegistry,adapter:EngineAdapter,root:string,baseSha:string,forgeDir:string,worktrees:WorktreeEntry[],onEvent?:ForgeEventCallback,signal?:AbortSignal,eventType:string,eventData?:Record<string,unknown>,worktreePath?:string,forgeMode?:'implement'|'improve'|'validate',requireDiff?:boolean,baselinePasses?:boolean,acceptReviewOutput?:boolean}): Promise<{result:EngineResult,metric:DispatchMetric,dispatchResult:any,worktreePath:string}> {
  const engine = opts.registry.get(opts.engineId);
  const forgeMode = resolveForgeMode(opts.forgeMode);
  const requireDiff = resolveForgeRequireDiff(forgeMode, opts.requireDiff);
  const acceptReviewOutput = resolveForgeAcceptReviewOutput(forgeMode, opts.acceptReviewOutput);
  const dispatchTimeout = resolveForgeDispatchTimeout(engine, opts.config);
  const wtPath = opts.worktreePath ?? join(opts.forgeDir, `wt-${opts.engineId}`);
  worktreeCreate(opts.root, wtPath, opts.baseSha);
  opts.worktrees.push({ engineId: opts.engineId, path: wtPath, repoRoot: opts.root });
  emitForgeEvent(opts.onEvent, 'engine:worktree', opts.engineId, { engineId: opts.engineId, worktreePath: wtPath, phase: opts.metricPhase });

  emitForgeEvent(opts.onEvent, opts.eventType, opts.engineId, opts.eventData);

  const dispatchStart = Date.now();
  let dispatchDurationMs = 0;
  let dispatchResult: any;
  // Forge is a code-changing workflow. API-only engines must run through
  // the tool-using agent loop; plain API chat can only return text and will
  // never modify the worktree.
  const useAgent = !!opts.adapter.dispatchAgent && (!!engine.agent || !!engine.api);
  const onSpawn = (pid: number) => emitForgeEvent(opts.onEvent, 'engine:pid', opts.engineId, { engineId: opts.engineId, pid, phase: opts.metricPhase });
  try {
    if (useAgent) {
      dispatchResult = await opts.adapter.dispatchAgent!({
        engine,
        prompt: opts.prompt,
        cwd: wtPath,
        mode: 'agent',
        timeout: dispatchTimeout,
        outputDir: opts.forgeDir,
        signal: opts.signal,
        onSpawn,
      });
    } else {
      dispatchResult = await opts.adapter.dispatch({
        engine,
        prompt: opts.prompt,
        cwd: wtPath,
        mode: opts.dispatchMode,
        timeout: dispatchTimeout,
        outputDir: opts.forgeDir,
        signal: opts.signal,
        onSpawn,
      });
    }
    const dispatchExitCode = typeof dispatchResult?.exitCode === 'number' ? dispatchResult.exitCode : 0;
    if (dispatchResult?.timedOut) {
      const stderr = dispatchResult?.stderr ? `: ${String(dispatchResult.stderr).slice(0, 240).replace(/\s+/g, ' ').trim()}` : '';
      dispatchResult = {
        ...dispatchResult,
        stdout: `${dispatchResult?.stdout ?? ''}\n[agon] dispatch timed out after ${dispatchTimeout}s${stderr}; harvesting candidate worktree for fitness.\n`,
      };
    } else if (dispatchExitCode !== 0) {
      const reason = `dispatch exited with code ${dispatchExitCode}`;
      const stderr = dispatchResult?.stderr ? `: ${String(dispatchResult.stderr).slice(0, 240).replace(/\s+/g, ' ').trim()}` : '';
      throw new Error(`${reason}${stderr}`);
    }
  } finally {
    dispatchDurationMs = Date.now() - dispatchStart;
    emitForgeEvent(opts.onEvent, 'engine:pid-clear', opts.engineId, { engineId: opts.engineId, phase: opts.metricPhase });
  }

  const fitnessStart = Date.now();
  const result = await runFitness({
    engineId: opts.engineId,
    worktreePath: wtPath,
    fitnessCmd: opts.fitnessCmd,
    timeout: opts.config.forgeFitnessTimeout,
    forgeDir: opts.forgeDir,
    requireDiff,
  });
  const fitnessDurationMs = Date.now() - fitnessStart;
  if (result.diffLines === 0) {
    const noDiff = classifyNoDiffForgeResult({
      stdout: String(dispatchResult?.stdout ?? ''),
      timedOut: dispatchResult?.timedOut ?? false,
      exitCode: typeof dispatchResult?.exitCode === 'number' ? dispatchResult.exitCode : 0,
      fitnessPassed: result.fitnessPassed === true,
      baselinePasses: opts.baselinePasses === true,
      mode: forgeMode,
      requireDiff,
      acceptReviewOutput,
    });
    result.status = noDiff.status;
    result.pass = noDiff.pass;
    result.score = noDiff.score;
    result.engineCompleted = noDiff.engineCompleted;
    result.reason = noDiff.reason;
  } else {
    result.status = result.pass ? 'passed' : 'fitness_failed';
    result.engineCompleted = !(dispatchResult?.timedOut ?? false);
    result.reason = result.pass ? undefined : 'fitness_failed';
  }
  opts.onEvent?.({ type: opts.metricPhase.includes('stage1') ? 'stage1:score' : 'stage2:score', engineId: opts.engineId, data: { engineId: opts.engineId, score: result.score, pass: result.pass, worktreePath: wtPath } });

  const promptTokens = estimateTokens(opts.prompt);
  const responseTokens = dispatchResult?.stdout ? estimateTokens(dispatchResult.stdout) : 0;
  const metric: DispatchMetric = {
    engineId: opts.engineId,
    phase: opts.metricPhase,
    dispatchDurationMs,
    fitnessDurationMs,
    totalDurationMs: dispatchDurationMs + fitnessDurationMs,
    pass: result.pass,
    score: result.score,
    timedOut: dispatchResult?.timedOut ?? false,
    tokens: { prompt: promptTokens, response: responseTokens, costUsd: estimateCost(opts.engineId, promptTokens + responseTokens) },
  };
  result.dispatchStdout = dispatchResult?.stdout?.slice(0, 5000) ?? '';
  return { result, metric, dispatchResult, worktreePath: wtPath };
}

// @kern-source: stages:226
export async function runBaseline(opts: {cwd:string, baseSha:string, fitnessCmd:string, fitnessTimeout:number, forgeDir:string, onEvent?:ForgeEventCallback}): Promise<boolean> {
  opts.onEvent?.({ type: 'baseline:start' });

  const root = repoRoot(opts.cwd);
  const baselineWt = join(opts.forgeDir, 'baseline-worktree');

  worktreeCreate(root, baselineWt, opts.baseSha);
  try {
    const result = await runFitness({
      engineId: 'baseline',
      worktreePath: baselineWt,
      fitnessCmd: opts.fitnessCmd,
      timeout: opts.fitnessTimeout,
      forgeDir: opts.forgeDir,
    });

    opts.onEvent?.({ type: 'baseline:done', data: { passes: result.pass } });
    return result.pass;
  } finally {
    worktreeRemoveBestEffort(root, baselineWt);
  }
}

// @kern-source: stages:250
export async function runStage1(opts: {starter:string, forgePrompt:string, fitnessCmd:string, config:Required<AgonConfig>, registry:EngineRegistry, adapter:EngineAdapter, cwd:string, baseSha:string, forgeDir:string, worktrees:WorktreeEntry[], onEvent?:ForgeEventCallback, signal?:AbortSignal, taskClass?:string, enginePrompts?:Map<string,string>, forgeMode?:'implement'|'improve'|'validate', requireDiff?:boolean, baselinePasses?:boolean, acceptReviewOutput?:boolean}): Promise<StageResult> {
  opts.onEvent?.({ type: 'stage1:start', engineId: opts.starter });
  const root = repoRoot(opts.cwd);
  const engineResults = new Map<string, EngineResult>();
  const metrics: DispatchMetric[] = [];
  try {
    const attempt = await runForgeEngineAttempt({ engineId: opts.starter, prompt: opts.forgePrompt, dispatchMode: 'exec', metricPhase: 'stage1', fitnessCmd: opts.fitnessCmd, config: opts.config, registry: opts.registry, adapter: opts.adapter, root: root, baseSha: opts.baseSha, forgeDir: opts.forgeDir, worktrees: opts.worktrees, onEvent: opts.onEvent, signal: opts.signal, eventType: 'stage1:dispatch', forgeMode: opts.forgeMode, requireDiff: opts.requireDiff, baselinePasses: opts.baselinePasses, acceptReviewOutput: opts.acceptReviewOutput });
    engineResults.set(opts.starter, attempt.result);
    metrics.push(attempt.metric);
  } catch (err) {
    const error = formatDispatchError(err);
    const elapsed = 0;
    console.warn(`[agon] forge stage1: engine ${opts.starter} failed: ${error}`);
    emitForgeEvent(opts.onEvent, 'engine:failed', opts.starter, { engineId: opts.starter, phase: 'stage1', error: error });
    const failed = makeFailedResult(opts.starter, error, elapsed);
    engineResults.set(opts.starter, failed);
    metrics.push({ engineId: opts.starter, phase: 'stage1', dispatchDurationMs: elapsed, totalDurationMs: elapsed, error: error });
  }
  const successful = [...engineResults.values()].filter((r) => r.pass);
  const result = successful.sort((a, b) => b.score - a.score)[0] ?? engineResults.get(opts.starter);
  // lintWarnings and styleScore are currently hardcoded (0 and 100) in fitness.kern,
  // so those checks are no-ops. Gate on what matters: pass + score threshold.
  const accepted = !(!result?.pass) && result.score >= opts.config.forgeAutoAcceptScore;
  if (accepted) {
    opts.onEvent?.({ type: 'stage1:accepted', engineId: result!.engineId, data: { score: result.score } });
  }
  return { engineResults: engineResults, accepted: accepted, winner: result?.pass ? result.engineId : null, metrics: metrics };
}

// @kern-source: stages:277
export async function runStage2(opts: {challengers:string[], forgePrompt:string, enginePrompts?:Map<string,string>, fitnessCmd:string, config:Required<AgonConfig>, registry:EngineRegistry, adapter:EngineAdapter, cwd:string, baseSha:string, forgeDir:string, existingResults:Map<string,EngineResult>, worktrees:WorktreeEntry[], onEvent?:ForgeEventCallback, signal?:AbortSignal, onResult?:(engineId:string,result:EngineResult,metric:DispatchMetric)=>'continue'|'finalize'|void, abortControllers?: Map<string,AbortController>, forgeMode?: 'implement'|'improve'|'validate', requireDiff?: boolean, baselinePasses?: boolean, acceptReviewOutput?: boolean}): Promise<StageResult> {
  opts.onEvent?.({ type: 'stage2:start' });

  const root = repoRoot(opts.cwd);

  const metrics: DispatchMetric[] = [];
  const published = new Set<string>();
  const abortControllers = opts.abortControllers ?? new Map<string, AbortController>();
  const finalizeResolvers = new Map<string, () => void>();
  let finalizeRequested = false;
  const makeFinalizedAttempt = (engineId: string, elapsedMs: number) => {
    const error = 'stage2 finalized by caller; engine aborted before it settled';
    emitForgeEvent(opts.onEvent, 'engine:failed', engineId, { engineId, phase: 'stage2', error });
    const result = makeFailedResult(engineId, error, elapsedMs);
    const metric: DispatchMetric = {
      engineId,
      phase: 'stage2-follower',
      dispatchDurationMs: elapsedMs,
      totalDurationMs: elapsedMs,
      error,
    };
    return { result, metric, dispatchResult: null, worktreePath: join(opts.forgeDir, `wt-${engineId}`) };
  };
  const requestFinalize = () => {
    if (finalizeRequested) return;
    finalizeRequested = true;
    for (const [engineId, controller] of abortControllers) {
      if (!controller.signal.aborted) controller.abort();
      const resolveFinalize = finalizeResolvers.get(engineId);
      if (resolveFinalize) {
        finalizeResolvers.delete(engineId);
        resolveFinalize();
      }
    }
  };
  const publishResult = (engineId: string, result: EngineResult, metric: DispatchMetric) => {
    metrics.push(metric);
    if (!published.has(engineId)) {
      published.add(engineId);
      const control = opts.onResult?.(engineId, result, metric);
      if (control === 'finalize') requestFinalize();
    }
  };

  const challengerPromises = opts.challengers.map(async (engineId: string) => {
    // Use per-engine specialized prompt if available (role specialization)
    const engineStart = Date.now();
    const prompt = opts.enginePrompts?.get(engineId) ?? opts.forgePrompt;
    const engine = opts.registry.get(engineId);
    const dispatchTimeout = resolveForgeDispatchTimeout(engine, opts.config);
    const hardTimeoutMs = Math.max(5, dispatchTimeout + opts.config.forgeFitnessTimeout + 5) * 1000;
    const engineAbort = new AbortController();
    abortControllers.set(engineId, engineAbort);
    if (opts.signal) {
      if (opts.signal.aborted) engineAbort.abort();
      else opts.signal.addEventListener('abort', () => engineAbort.abort(), { once: true });
    }

    const attemptPromise = runForgeEngineAttempt({
      engineId,
      prompt,
      dispatchMode: 'exec',
      metricPhase: 'stage2-follower',
      fitnessCmd: opts.fitnessCmd,
      config: opts.config,
      registry: opts.registry,
      adapter: opts.adapter,
      root,
      baseSha: opts.baseSha,
      forgeDir: opts.forgeDir,
      worktrees: opts.worktrees,
      onEvent: opts.onEvent,
      signal: engineAbort.signal,
      eventType: 'stage2:dispatch',
      forgeMode: opts.forgeMode,
      requireDiff: opts.requireDiff,
      baselinePasses: opts.baselinePasses,
      acceptReviewOutput: opts.acceptReviewOutput,
    });
    let timeoutHandle: ReturnType<typeof setTimeout> | null = null;
    const timeoutPromise = new Promise<{result:EngineResult,metric:DispatchMetric,dispatchResult:any,worktreePath:string}>((resolve) => {
      timeoutHandle = setTimeout(() => {
        engineAbort.abort();
        const error = `stage2 engine timed out after ${Math.round(hardTimeoutMs / 1000)}s`;
        emitForgeEvent(opts.onEvent, 'engine:failed', engineId, { engineId, phase: 'stage2', error });
        const result = makeFailedResult(engineId, error, hardTimeoutMs);
        const metric: DispatchMetric = { engineId, phase: 'stage2-follower', dispatchDurationMs: hardTimeoutMs, totalDurationMs: hardTimeoutMs, error, timedOut: true };
        resolve({ result, metric, dispatchResult: null, worktreePath: join(opts.forgeDir, `wt-${engineId}`) });
      }, hardTimeoutMs);
    });
    const finalizePromise = new Promise<{result:EngineResult,metric:DispatchMetric,dispatchResult:any,worktreePath:string}>((resolve) => {
      const resolveFinalize = () => resolve(makeFinalizedAttempt(engineId, Date.now() - engineStart));
      finalizeResolvers.set(engineId, resolveFinalize);
      if (finalizeRequested) {
        finalizeResolvers.delete(engineId);
        engineAbort.abort();
        resolveFinalize();
      }
    });
    try {
      const attempt = await Promise.race([attemptPromise, timeoutPromise, finalizePromise]);
      if (timeoutHandle) clearTimeout(timeoutHandle);
      finalizeResolvers.delete(engineId);
      abortControllers.delete(engineId);
      publishResult(engineId, attempt.result, attempt.metric);
      return attempt.result;
    } catch (err) {
      if (timeoutHandle) clearTimeout(timeoutHandle);
      finalizeResolvers.delete(engineId);
      abortControllers.delete(engineId);
      const error = formatDispatchError(err);
      console.warn(`[agon] forge stage2: engine ${engineId} failed: ${error}`);
      emitForgeEvent(opts.onEvent, 'engine:failed', engineId, { engineId, phase: 'stage2', error });
      const failed = makeFailedResult(engineId, error);
      const metric: DispatchMetric = {
        engineId,
        phase: 'stage2-follower',
        dispatchDurationMs: 0,
        totalDurationMs: 0,
        error,
      };
      publishResult(engineId, failed, metric);
      return failed;
    }
  });

  // Use Promise.allSettled — one slow/broken engine must NOT stall the others.
  // Promise.allSettled preserves input order, so settled[i] corresponds to opts.challengers[i].
  // Index-based correlation avoids the O(n²) settled.indexOf(outcome) lookup and is robust to
  // duplicate rejection objects.
  const settled = await Promise.allSettled(challengerPromises);

  const allResults = new Map(opts.existingResults);
  for (let i = 0; i < settled.length; i++) {
    const outcome = settled[i];
    if (outcome.status === 'fulfilled') {
      allResults.set(outcome.value.engineId, outcome.value);
    } else {
      const failedId = opts.challengers[i];
      const error = formatDispatchError(outcome.reason);
      console.warn(`[agon] forge stage2: engine ${failedId} failed: ${error}`);
      emitForgeEvent(opts.onEvent, 'engine:failed', failedId, { engineId: failedId, phase: 'stage2', error });
      const failed = makeFailedResult(failedId, error);
      const metric: DispatchMetric = {
        engineId: failedId,
        phase: 'stage2-follower',
        dispatchDurationMs: 0,
        totalDurationMs: 0,
        error,
      };
      allResults.set(failedId, failed);
      publishResult(failedId, failed, metric);
    }
  }

  opts.onEvent?.({ type: 'stage2:done', data: { resultCount: allResults.size } });

  return { engineResults: allResults, accepted: false, winner: null, metrics };
}

// @kern-source: stages:438
export async function runStage2WithPeek(opts: {challengers:string[], forgePrompt:string, enginePrompts?:Map<string,string>, fitnessCmd:string, config:Required<AgonConfig>, registry:EngineRegistry, adapter:EngineAdapter, cwd:string, baseSha:string, forgeDir:string, existingResults:Map<string,EngineResult>, worktrees:WorktreeEntry[], onEvent?:ForgeEventCallback, signal?:AbortSignal, forgeMode?:'implement'|'improve'|'validate', requireDiff?:boolean, baselinePasses?:boolean, acceptReviewOutput?:boolean}): Promise<StageResult> {
  if (opts.challengers.length <= 1) {
    // Only one challenger — no peek possible, use normal stage2
    return runStage2(opts);
  }

  opts.onEvent?.({ type: 'stage2:start', data: { strategy: 'peek' } });

  const root = repoRoot(opts.cwd);

  // Phase 1: dispatch the scout (first challenger) alone
  const scoutId = opts.challengers[0];
  const followers = opts.challengers.slice(1);

  const scoutWt = join(opts.forgeDir, `wt-${scoutId}`);

  const metrics: DispatchMetric[] = [];

  const scoutPrompt = opts.enginePrompts?.get(scoutId) ?? opts.forgePrompt;
  const scoutDispatchStart = Date.now();
  let scoutDispatchResult: any;
  let scoutResult: EngineResult;
  let scoutResultId = scoutId;
  let peekContext = '';
  try {
    const scoutAttempt = await runForgeEngineAttempt({
      engineId: scoutId,
      prompt: scoutPrompt,
      dispatchMode: 'exec',
      metricPhase: 'stage2-scout',
      fitnessCmd: opts.fitnessCmd,
      config: opts.config,
      registry: opts.registry,
      adapter: opts.adapter,
      root,
      baseSha: opts.baseSha,
      forgeDir: opts.forgeDir,
      worktrees: opts.worktrees,
      onEvent: opts.onEvent,
      signal: opts.signal,
      eventType: 'stage2:dispatch',
      eventData: { phase: 'scout' },
      worktreePath: scoutWt,
      forgeMode: opts.forgeMode,
      requireDiff: opts.requireDiff,
      baselinePasses: opts.baselinePasses,
      acceptReviewOutput: opts.acceptReviewOutput,
    });
    scoutDispatchResult = scoutAttempt.dispatchResult;
    scoutResult = scoutAttempt.result;
    scoutResultId = scoutId;

    // Build typed StageContext from scout's results (replaces raw diff slice)
    const scoutDiff = worktreeDiff(scoutWt);
    const scoutStdout = scoutDispatchResult?.stdout ?? '';

    // Build StageContext — structured learnings for followers
    const stageCtx: StageContext = buildStageContext({
      engineId: scoutId,
      pass: scoutResult.pass,
      score: scoutResult.score,
      prompt: scoutPrompt,
      diff: scoutDiff,
      fitnessLogPath: scoutResult.fitnessLogPath,
      dispatchStdout: scoutStdout,
    });

    peekContext = scoutDiff
      ? `\n\n${renderStageContext(stageCtx)}`
      : '';

    metrics.push(scoutAttempt.metric);
  } catch (err) {
    const error = formatDispatchError(err);
    const elapsed = Date.now() - scoutDispatchStart;
    console.warn(`[agon] forge stage2-peek scout ${scoutId} failed: ${error}`);
    emitForgeEvent(opts.onEvent, 'engine:failed', scoutId, { engineId: scoutId, phase: 'stage2-scout', error });
    scoutResult = makeFailedResult(scoutId, error, elapsed);
    metrics.push({
      engineId: scoutId,
      phase: 'stage2-scout',
      dispatchDurationMs: elapsed,
      totalDurationMs: elapsed,
      error,
    });
  }

  // Phase 2: dispatch followers with peek context
  const followerPromises = followers.map(async (engineId: string) => {
    const basePrompt = opts.enginePrompts?.get(engineId) ?? opts.forgePrompt;
    const prompt = basePrompt + peekContext;

    const attempt = await runForgeEngineAttempt({
      engineId,
      prompt,
      dispatchMode: 'exec',
      metricPhase: 'stage2-follower',
      fitnessCmd: opts.fitnessCmd,
      config: opts.config,
      registry: opts.registry,
      adapter: opts.adapter,
      root,
      baseSha: opts.baseSha,
      forgeDir: opts.forgeDir,
      worktrees: opts.worktrees,
      onEvent: opts.onEvent,
      signal: opts.signal,
      eventType: 'stage2:dispatch',
      eventData: { phase: 'follower', hasPeek: !!peekContext },
      forgeMode: opts.forgeMode,
      requireDiff: opts.requireDiff,
      baselinePasses: opts.baselinePasses,
      acceptReviewOutput: opts.acceptReviewOutput,
    });
    metrics.push(attempt.metric);
    return attempt.result;
  });

  // Use Promise.allSettled — one slow/broken engine must NOT stall the others.
  // Index-based correlation: settled[i] corresponds to followers[i].
  const settled = await Promise.allSettled(followerPromises);

  const allResults = new Map(opts.existingResults);
  allResults.set(scoutResultId, scoutResult);
  for (let i = 0; i < settled.length; i++) {
    const outcome = settled[i];
    if (outcome.status === 'fulfilled') {
      allResults.set(outcome.value.engineId, outcome.value);
    } else {
      const failedId = followers[i];
      const error = formatDispatchError(outcome.reason);
      console.warn(`[agon] forge stage2-peek: engine ${failedId} failed: ${error}`);
      emitForgeEvent(opts.onEvent, 'engine:failed', failedId, { engineId: failedId, phase: 'stage2-follower', error });
      allResults.set(failedId, makeFailedResult(failedId, error));
      metrics.push({
        engineId: failedId,
        phase: 'stage2-follower',
        dispatchDurationMs: 0,
        totalDurationMs: 0,
        error,
      });
    }
  }

  opts.onEvent?.({ type: 'stage2:done', data: { resultCount: allResults.size, strategy: 'peek' } });

  return { engineResults: allResults, accepted: false, winner: null, metrics };
}
